import{_ as o,C as s,o as e,c as d,a3 as t,b as n,w as r,a as l,E as c,a4 as m}from"./chunks/framework.DACwFHq9.js";const x=JSON.parse('{"title":"Diagrams","description":"Create flowcharts and visual diagrams in Notely using Mermaid syntax or the Excalidraw visual canvas.","frontmatter":{"title":"Diagrams","description":"Create flowcharts and visual diagrams in Notely using Mermaid syntax or the Excalidraw visual canvas.","keywords":"mermaid, excalidraw, diagrams, flowchart, sequence diagram, gantt, whiteboard, visual editor","category":"Editor"},"headers":[],"relativePath":"editor/diagrams.md","filePath":"editor/diagrams.md","lastUpdated":1784057516000}'),h={name:"editor/diagrams.md"};function g(p,a,w,u,b,k){const i=s("Mermaid");return e(),d("div",null,[a[1]||(a[1]=t('<h1 id="diagrams" tabindex="-1">Diagrams <a class="header-anchor" href="#diagrams" aria-label="Permalink to &quot;Diagrams&quot;">​</a></h1><p>Notely supports three diagram formats: <strong>Mermaid</strong> for text-based diagrams written in code, <strong>Excalidraw</strong> for freehand whiteboard-style drawing, and <strong>Draw.io</strong> for structured technical schemas and system architectures.</p><h2 id="mermaid-diagrams" tabindex="-1">Mermaid Diagrams <a class="header-anchor" href="#mermaid-diagrams" aria-label="Permalink to &quot;Mermaid Diagrams&quot;">​</a></h2><p><a href="https://mermaid.js.org/" target="_blank" rel="noreferrer">Mermaid</a> lets you create diagrams using a simple text syntax. Notely renders them live in Preview and Split modes.</p><h3 id="insert-a-mermaid-block" tabindex="-1">Insert a Mermaid Block <a class="header-anchor" href="#insert-a-mermaid-block" aria-label="Permalink to &quot;Insert a Mermaid Block&quot;">​</a></h3><ol><li>In Edit mode, click <strong>Diagram → Mermaid</strong> in the toolbar.</li><li>A Mermaid code block is inserted at the cursor.</li><li>Write your Mermaid syntax inside the block.</li><li>Switch to Split or Preview to see the rendered diagram.</li></ol><h3 id="diagram-types" tabindex="-1">Diagram Types <a class="header-anchor" href="#diagram-types" aria-label="Permalink to &quot;Diagram Types&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">```mermaid</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Open workspace] --&gt; B[Create note]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{Write content}</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Save note]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[Commit to Git]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">```</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><table tabindex="0"><thead><tr><th>Type</th><th>Keyword</th><th>Use for</th></tr></thead><tbody><tr><td>Flowchart</td><td><code>graph TD</code> / <code>graph LR</code></td><td>Processes, decisions, flows</td></tr><tr><td>Sequence</td><td><code>sequenceDiagram</code></td><td>API calls, user interactions</td></tr><tr><td>Gantt</td><td><code>gantt</code></td><td>Project timelines</td></tr><tr><td>Class</td><td><code>classDiagram</code></td><td>Object relationships</td></tr><tr><td>State</td><td><code>stateDiagram-v2</code></td><td>State machines</td></tr><tr><td>ER</td><td><code>erDiagram</code></td><td>Database schemas</td></tr><tr><td>Pie</td><td><code>pie</code></td><td>Data proportions</td></tr></tbody></table><h3 id="example-—-git-workflow" tabindex="-1">Example — Git Workflow <a class="header-anchor" href="#example-—-git-workflow" aria-label="Permalink to &quot;Example — Git Workflow&quot;">​</a></h3>',10)),(e(),n(m,null,{default:r(()=>[c(i,{id:"mermaid-138",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5BEdit%20note%5D%20--%3E%20B%5BStage%20changes%5D%0A%20%20%20%20B%20--%3E%20C%5BWrite%20commit%20message%5D%0A%20%20%20%20C%20--%3E%20D%5BCommit%5D%0A%20%20%20%20D%20--%3E%20E%7BPush%20to%20remote%3F%7D%0A%20%20%20%20E%20--%20Yes%20--%3E%20F%5Bgit%20push%5D%0A%20%20%20%20E%20--%20No%20--%3E%20G%5BStay%20local%5D%0A"})]),fallback:r(()=>[...a[0]||(a[0]=[l(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=t('<h3 id="troubleshooting-mermaid" tabindex="-1">Troubleshooting Mermaid <a class="header-anchor" href="#troubleshooting-mermaid" aria-label="Permalink to &quot;Troubleshooting Mermaid&quot;">​</a></h3><p>If your diagram does not render:</p><ol><li>Switch to Split mode to see both the source and the error message.</li><li>Check for syntax errors — Mermaid is strict about arrow direction (<code>--&gt;</code> not <code>→</code>).</li><li>Validate with the <a href="https://mermaid.live/" target="_blank" rel="noreferrer">Mermaid Live Editor</a>.</li></ol><hr><h2 id="excalidraw-diagrams" tabindex="-1">Excalidraw Diagrams <a class="header-anchor" href="#excalidraw-diagrams" aria-label="Permalink to &quot;Excalidraw Diagrams&quot;">​</a></h2><p><a href="https://excalidraw.com/" target="_blank" rel="noreferrer">Excalidraw</a> provides a whiteboard canvas for freehand drawing, annotated shapes, and visual diagrams embedded directly in your notes.</p><h3 id="insert-an-excalidraw-diagram" tabindex="-1">Insert an Excalidraw Diagram <a class="header-anchor" href="#insert-an-excalidraw-diagram" aria-label="Permalink to &quot;Insert an Excalidraw Diagram&quot;">​</a></h3><ol><li>Click <strong>Diagram → Excalidraw</strong> in the toolbar.</li><li>An Excalidraw block is inserted in the note.</li><li>In Preview mode, the Excalidraw canvas opens.</li><li>Draw your diagram, then click <strong>Save</strong> to embed it.</li><li>The diagram is stored as a file in your workspace.</li></ol><h3 id="re-edit-an-existing-diagram" tabindex="-1">Re-Edit an Existing Diagram <a class="header-anchor" href="#re-edit-an-existing-diagram" aria-label="Permalink to &quot;Re-Edit an Existing Diagram&quot;">​</a></h3><ol><li>In Preview mode, click the <strong>Edit</strong> button on the Excalidraw preview.</li><li>The canvas reopens with your existing drawing.</li><li>Make changes, then click <strong>Save</strong>.</li></ol><h3 id="convert-an-image-to-excalidraw" tabindex="-1">Convert an Image to Excalidraw <a class="header-anchor" href="#convert-an-image-to-excalidraw" aria-label="Permalink to &quot;Convert an Image to Excalidraw&quot;">​</a></h3><p>You can convert any workspace image into an Excalidraw diagram so you can annotate or draw on top of it:</p><ol><li>In Preview mode, right-click on any workspace image.</li><li>Select <strong>Edit with Excalidraw</strong>.</li><li>The image is placed on the Excalidraw canvas as a resizable background element.</li><li>Draw annotations, arrows, or labels on top.</li><li>Click <strong>Save</strong> to replace the image reference with the Excalidraw diagram.</li></ol><h3 id="restore-the-original-image" tabindex="-1">Restore the Original Image <a class="header-anchor" href="#restore-the-original-image" aria-label="Permalink to &quot;Restore the Original Image&quot;">​</a></h3><p>If you converted an image to Excalidraw and want to revert to the original:</p><ol><li>In Preview mode, right-click the Excalidraw preview.</li><li>Select <strong>Restore original image</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Restore Availability</p><p>The <strong>Restore original image</strong> option only appears for Excalidraw diagrams that were created from an image conversion. Diagrams created from scratch do not show this option.</p></div><hr><h2 id="draw-io-diagrams" tabindex="-1">Draw.io Diagrams <a class="header-anchor" href="#draw-io-diagrams" aria-label="Permalink to &quot;Draw.io Diagrams&quot;">​</a></h2><p><a href="https://embed.diagrams.net/" target="_blank" rel="noreferrer">Draw.io</a> (diagrams.net) is integrated into Notely for precise, professional engineering schematics, UML designs, and network/cloud architectures.</p><h3 id="insert-a-draw-io-diagram" tabindex="-1">Insert a Draw.io Diagram <a class="header-anchor" href="#insert-a-draw-io-diagram" aria-label="Permalink to &quot;Insert a Draw.io Diagram&quot;">​</a></h3><ol><li>Click the <strong>Insert Diagram</strong> icon (<code>⚡</code>) on the toolbar.</li><li>Click <strong>Draw.io</strong>.</li><li>In Preview mode, click on the placeholder to open the Draw.io editor.</li><li>Build your diagram and click <strong>Save Diagram</strong>.</li><li>The diagram saves XML source metadata to <code>media/draw.io/*.drawio</code> and renders a preview image to <code>media/draw.io/*.png</code>.</li></ol><h3 id="import-diagrams-via-drag-and-drop" tabindex="-1">Import Diagrams via Drag and Drop <a class="header-anchor" href="#import-diagrams-via-drag-and-drop" aria-label="Permalink to &quot;Import Diagrams via Drag and Drop&quot;">​</a></h3><p>Drop any existing <code>.drawio</code> or <code>.drawio.xml</code> file directly into the Markdown Editor. Notely will parse the file, copy it into the workspace media directory, and embed it as an interactive diagram block.</p><hr><h2 id="choosing-a-diagram-tool" tabindex="-1">Choosing a Diagram Tool <a class="header-anchor" href="#choosing-a-diagram-tool" aria-label="Permalink to &quot;Choosing a Diagram Tool&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Mermaid</th><th>Excalidraw</th><th>Draw.io</th></tr></thead><tbody><tr><td><strong>Best for</strong></td><td>Fast text-based flows, timelines</td><td>Casual sketching, wireframes</td><td>Engineering schematics, network charts</td></tr><tr><td><strong>Editing</strong></td><td>Text syntax</td><td>Visual canvas</td><td>Visual canvas</td></tr><tr><td><strong>Storage</strong></td><td>Plain Markdown text</td><td>XML drawing + PNG preview</td><td>XML drawing + PNG preview</td></tr><tr><td><strong>Offline</strong></td><td>✓</td><td>✓</td><td>✓</td></tr></tbody></table>',27))])}const f=o(h,[["render",g]]);export{x as __pageData,f as default};
